// imageResolution returns a human-readable resolution string.
func imageResolution(w, h int) string {
	if w > 0 && h > 0 {
		return strconv.Itoa(w) + "x" + strconv.Itoa(h)
	}
	return ""
}

func imageExistsForType(a artist.Artist, t string) bool {
	switch t {
	case "thumb":
		return a.ThumbExists
	case "fanart":
		return a.FanartExists
	case "logo":
		return a.LogoExists
	case "banner":
		return a.BannerExists
	default:
		return false
	}
}

// imageTypeLabel returns a display label for an image slot, using the
// platform profile name when available for profile-aware terminology.
func imageTypeLabel(t, profileName string) string {
	label := img.ImageTermFor(t, profileName)
	if label == "" {
		return t
	}
	return label
}

